// Offload heavy computation to background thread
void AMyActor::StartHeavyWork() {
    // Capture values (not UObject pointers) for thread safety
    TArray<FVector> PointsCopy = Points;
    TWeakObjectPtr<AMyActor> WeakThis(this);

    AsyncTask(ENamedThreads::AnyBackgroundThreadNormalTask, [PointsCopy, WeakThis]() {
        // Heavy computation on background thread
        TArray<FVector> Results = ProcessPoints(PointsCopy);

        // Marshal result back to Game Thread
        AsyncTask(ENamedThreads::GameThread, [WeakThis, Results = MoveTemp(Results)]() {
            if (WeakThis.IsValid()) {
                WeakThis->OnComputationComplete(Results);
            }
        });
    });
}

// ParallelFor — process array in parallel
TArray<FVector> Positions;
Positions.SetNum(10000);
ParallelFor(Positions.Num(), [&Positions](int32 Index) {
    // Each index runs on a different thread — no shared state!
    Positions[Index] = ComputePosition(Index);
});

